import{_ as a,o as i,c as g,a2 as u}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"1.4 采矿","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 根据采矿的性质我们可以将采矿分为两类： ①普通采矿②特殊采矿 普通采矿根据方式不同，可以分为以下三种： ③野外挖矿④矿脉农场采矿⑤大小矿机采矿 特殊采矿根据对象不同，可以分为以下几种： ⑥","frontmatter":{"title":"1.4 采矿","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 根据采矿的性质我们可以将采矿分为两类： ①普通采矿②特殊采矿 普通采矿根据方式不同，可以分为以下三种： ③野外挖矿④矿脉农场采矿⑤大小矿机采矿 特殊采矿根据对象不同，可以分为以下几种： ⑥","outline":"deep"},"headers":[],"relativePath":"life/1-4.md","filePath":"life/1-4.md","lastUpdated":1782387794000}'),e={name:"life/1-4.md"};function t(l,s,p,r,o,f){return i(),g("div",null,[...s[0]||(s[0]=[u('<h1 id="_1-4-采矿" tabindex="-1">1.4 采矿 <a id="s066-537da064"></a> <a class="header-anchor" href="#_1-4-采矿" aria-label="Permalink to &quot;1.4 采矿 &lt;a id=&quot;s066-537da064&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-4-1-采矿的种类" tabindex="-1">1.4.1 采矿的种类 <a id="s067-d1e13697"></a> <a class="header-anchor" href="#_1-4-1-采矿的种类" aria-label="Permalink to &quot;1.4.1 采矿的种类 &lt;a id=&quot;s067-d1e13697&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>根据采矿的性质我们可以将采矿分为两类：</p><p>①普通采矿②特殊采矿</p><p>普通采矿根据方式不同，可以分为以下三种：</p><p>③野外挖矿④矿脉农场采矿⑤大小矿机采矿</p><p>特殊采矿根据对象不同，可以分为以下几种：</p><p>⑥挖未鉴定的矿脉⑦挖碎星矿⑧挖亚纳碎石</p><h2 id="_1-4-2-影响采矿时间的因素" tabindex="-1">1.4.2 影响采矿时间的因素 <a id="s068-a8dfd1b7"></a> <a class="header-anchor" href="#_1-4-2-影响采矿时间的因素" aria-label="Permalink to &quot;1.4.2 影响采矿时间的因素 &lt;a id=&quot;s068-a8dfd1b7&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>影响采矿时间的因素仅有以下六种：</p><p>1）使用床睡觉后获得的生活相关活动施法时间减少的BUFF</p><p>2）熟练度时装自带生活相关活动施法时间减少的效果</p><p>3）玩家熟练度减少施法时间</p><p>4）对应晨露时装在连续3 次采矿后的减少施法时间的BUFF</p><p>5）家具提供的生活相关活动施法时间减少的BUFF</p><p>6）快速生产卷轴的BUFF</p><h2 id="_1-4-3-野外挖矿" tabindex="-1">1.4.3 野外挖矿 <a id="s069-45a93de5"></a> <a class="header-anchor" href="#_1-4-3-野外挖矿" aria-label="Permalink to &quot;1.4.3 野外挖矿 &lt;a id=&quot;s069-45a93de5&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>野外采矿需要我们先前往野外的矿点。常用的矿点有以下几个：</p><p>碎石平原</p><p>黎利尔丘陵</p><p>虎脊山脉</p><p>黎明半岛</p><p>伊尼斯泰尔</p><p>到达矿点后，我们要先对石碓进行交互。如下图所示：</p><p>挖掉石碓后，如果会出现贵金属矿脉，则会有闪光特效，如无则可以去挖下一个</p><p>石碓。贵金属矿脉如下图所示：</p><p>挖掉贵金属矿脉后，如果会出现未鉴定的矿脉，则会有闪光特效，如无则可以去挖下一个石碓。</p><p>未鉴定矿脉如上图，需要未加成熟练度至少达到过一次23W 获取称号后才能进行开采。熟练度要求可以在熟练度降级后通过装备、BUFF、时装来满足。</p><p>开采未鉴定矿脉会采出以下3 种矿石：</p><p>都需要使用矿石鉴定器才能鉴定出产物，蓝色出的东西最值钱。</p><p>鉴定器如下图：</p><p>需要铜锭X3，木材X1.</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1096.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1097.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1098.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1103.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1104.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1109.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1110.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1115.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1116.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1117.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1118.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1123.jpeg" alt="图示：1.4.3 野外挖矿" loading="lazy"></figure><h2 id="_1-4-4-矿脉农场采矿" tabindex="-1">1.4.4 矿脉农场采矿 <a id="s070-808b296c"></a> <a class="header-anchor" href="#_1-4-4-矿脉农场采矿" aria-label="Permalink to &quot;1.4.4 矿脉农场采矿 &lt;a id=&quot;s070-808b296c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>使用这种方法需要玩家拥有一个矿脉农场，开始采集后30 分钟后开始一次判定，</p><p>大概率是普通矿脉。</p><p>30 分钟后如果是普通矿脉，则再过X 小时可以收获一次积累3 次的普通矿脉，</p><p>如果是惊喜矿脉则是再过X 小时可以收获一次积累3 次的惊喜矿脉，低概率收获宝石。</p><p>如果你想刷惊喜矿脉可以在积累一次普通的情况下就去收获，以重置矿脉判定。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1124.jpeg" alt="图示：1.4.4 矿脉农场采矿" loading="lazy"></figure><h2 id="_1-4-5-大小矿机采矿" tabindex="-1">1.4.5 大小矿机采矿 <a id="s071-8fe5bd70"></a> <a class="header-anchor" href="#_1-4-5-大小矿机采矿" aria-label="Permalink to &quot;1.4.5 大小矿机采矿 &lt;a id=&quot;s071-8fe5bd70&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>使用这种方法需要玩家在空地上放置一个采矿机，每隔X 小时可以收获一次，低概率收获宝石。大矿机为3.5 小时一收，小矿机为6 小时收一次。大小矿机如下图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1130.jpeg" alt="图示：1.4.5 大小矿机采矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1131.jpeg" alt="图示：1.4.5 大小矿机采矿" loading="lazy"></figure><h2 id="_1-4-6-挖碎星矿" tabindex="-1">1.4.6 挖碎星矿 <a id="s072-d4750371"></a> <a class="header-anchor" href="#_1-4-6-挖碎星矿" aria-label="Permalink to &quot;1.4.6 挖碎星矿 &lt;a id=&quot;s072-d4750371&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>碎星矿只能在十字星外边海底挖矿获得。碎星矿分布在岩浆附近和火山口附近。</p><p>地图位置如下：</p><p>下图不停冒气泡的黑色石碓的就是碎星矿：</p><p>挖碎星矿你需要提前准备呼吸器或者呼吸耳环。如下图所示：</p><p>最好是还能准备一个脚蹼和一个游泳耳环以及游泳速度称号。如下图：</p><p>碎星矿堆分布在海底火山口附近和岩浆附近。火山口在海面会有特效。岩浆虽然没有特效，但是可以将镜头切至水下看到。火山口特效和岩浆如图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1138.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1139.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1144.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1145.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1146.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1147.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1152.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1153.jpeg" alt="图示：1.4.6 挖碎星矿" loading="lazy"></figure><h2 id="_1-4-7-挖亚纳碎石" tabindex="-1">1.4.7 挖亚纳碎石 <a id="s073-cbc2f294"></a> <a class="header-anchor" href="#_1-4-7-挖亚纳碎石" aria-label="Permalink to &quot;1.4.7 挖亚纳碎石 &lt;a id=&quot;s073-cbc2f294&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>亚纳石碓分别在墟境之口在狂蟒墟境圈圈通道处。如图所示：</p><p>挖亚纳石碓需要熟练度至少有，如图所示;</p><p>亚纳碎石还可以通过挖去该地图矿洞内集中刷新的亚纳石碓获得，矿洞内的石碓产量更大，但有概率会吸引来其他玩家或者敌对玩家来抢夺石碓。矿洞位置如图：</p><p>矿洞需要一点点挖开，3 劳动力可以挖一次，如图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1158.jpeg" alt="图示：1.4.7 挖亚纳碎石" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1159.jpeg" alt="图示：1.4.7 挖亚纳碎石" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1165.jpeg" alt="图示：1.4.7 挖亚纳碎石" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1166.jpeg" alt="图示：1.4.7 挖亚纳碎石" loading="lazy"></figure>',80)])])}const m=a(e,[["render",t]]);export{c as __pageData,m as default};
